mapper.select:
select scro.refund_order_no,scro.order_no,scro.refund_amount,scro.refund_gift_amount,scro.refund_status,scro.create_time, scro.uid,u.nickname,u.avatar,u.phone from eb_shopping_credits_refund_order scro left join eb_user as u on scro.uid = u.id where scro.mer_id = #{merId}
and scro.refund_status = #{refundStatus}
and scro.order_no like CONCAT('%',#{orderNo},'%')
and scro.refund_order_no like CONCAT('%',#{refundOrderNo},'%')
and scro.create_time between #{startTime} and #{endTime}
and ( scro.uid like CONCAT('%',#{keywords},'%') or u.nickname like CONCAT('%',#{keywords},'%') or u.phone like CONCAT('%',#{keywords},'%') )
and scro.uid = #{uid}
and u.nickname like CONCAT('%',#{nickname},'%')
and u.phone like CONCAT('%',#{phone},'%')
order by scro.id desc
